  ('heelevel3-5ff21eeb-moex-00085', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲夫、乙妻攜全家老小出遊，因對振興五倍券使用上有所誤會，積欠旅遊業者丙新臺幣(下同)15 萬元未清償。甲夫月收10萬元，乙妻月收5萬元。下列敘述，何者正確？', '["依甲、乙之經濟能力，丙僅得向乙請求5萬元之給付", "依甲、乙之經濟能力，丙僅得向甲請求10萬元之給付", "丙得就15萬元之給付，主張甲、乙連帶負責", "夫妻各自對其債務負清償之責，丙僅得向簽約之甲請求15萬元之給付"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00086', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於收養關係之敘述，何者錯誤？', '["被收養者自收養關係成立之日，與其養父母成立擬制之親子關係", "養子女於收養關係存續中，與其本生父母之天然血親仍然存在", "養子女於收養關係存續中，與其本生父母之權利義務關係，處於停止狀態", "收養關係存續中，所謂直系血親卑親屬與父母關係，包含養子女與本生父母關係在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00087', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列何者不具有溯及效力？', '["認領", "法院認可收養", "裁判減輕扶養義務", "終止收養之撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00088', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於遺產繼承人之敘述，何者正確？', '["繼承人若有於繼承開始後死亡或喪失繼承權者，由其直系血親卑親屬代位繼承其應繼分", "繼承人對於被繼承人有重大之虐待或侮辱情事，並經被繼承人表示其不得繼承者，其繼承權喪失", "繼承人有數人，其中一人若受監護或輔助宣告者，法院得依其他繼承人之請求，宣告該繼承人 之繼承權喪失", "同一順序之繼承人有數人時，按人數平均繼承。但非婚生子女之應繼分，為婚生子女應繼分之 二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00089', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲死亡時，留下存款新臺幣（下同）240 萬元，有配偶乙、兄丙、姊丁及妹戊為其繼承人。丁應 可繼承多少甲之遺產？', '["40萬元", "60萬元", "80萬元", "120萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00090', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於代位繼承之敘述，何者錯誤？', '["代位繼承係以自己固有之繼承權直接繼承祖父母之遺產", "代位繼承係以自己固有之繼承權繼承父或母之權利", "孫對於祖父母之遺產，有無代位繼承之資格，自應以祖父母之繼承開始為標準而決定之", "子女對父或母之遺產拋棄繼承，不能即謂對祖父母之遺產拋棄代位繼承"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00091', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'essay', '甲將其名下價值新臺幣（下同）300 萬元之豪華轎車以 30萬元賣售其友
乙，雙方並辦妥所有權移轉登記。甲於當年度申報綜合所得稅時，申報
該筆財產交易所得為 0元。嗣遭國稅局查獲，認為甲之行為構成遺產及
贈與稅法（下稱遺贈稅法）第 5條第 2款之以顯著不相當之代價，讓與
財產，並就其差額部分課徵贈與稅。
試問：遺贈稅法第 5 條第 2款規定：「財產之移動，具有左列各款情形之
一者，以贈與論，依本法規定，課徵贈與稅：二、以顯著不相當之代價，
讓與財產、免除或承擔債務者，其差額部分。」該法條之立論基礎為何？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00092', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'essay', '甲營業人因竄改發票，導致虛報進項稅額逃漏營業稅，甲因同時觸犯稅捐
