  ('heelevel3-5ff21eeb-moex-00093', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲的房屋遭法拍，拍定價為500萬元，其積欠的債務及稅捐如下：①向好友借款100萬元，未設', '["向銀行抵押借款300萬元", "所得稅10萬元", "該法拍屋的房屋稅5萬元。依稅捐 稽徵法之規定，上開拍定價款應清償上開債務及稅捐之順序為何？", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
